Here is a C++ program to find the nth Fibonacci number using recursion:

```c++
#include <iostream>
using namespace std;

int fibonacci(int n) {
    if(n <= 1) {
        return n;
    }
    else {
        return fibonacci(n - 1) + fibonacci(n - 2);
    }
}

int main() {
    int n;
    cout << "Enter the number of the Fibonacci sequence: ";
    cin >> n;
    cout << "The " << n << "th Fibonacci number is: " << fibonacci(n) << endl;
    return 0;
}
```

Here is a Python function that uses the Boyer-Moore Voting Algorithm to find the majority element in a given integer array:

```python
def majority_element(nums):
    count = 0
    candidate = None
    for num in nums:
        if count == 0:
            candidate = num
            count = 1
        elif candidate == num:
            count += 1
        else:
            count -= 1
    return candidate
```

